import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;

import java.util.Map;
import java.util.concurrent.CompletableFuture;

@RestController
@RequestMapping("/webhook")
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/process")
    public ResponseEntity<String> processWebhook(@RequestBody Map<String, Object> payload) {
        try {
            String url = (String) payload.get("url");
            String method = (String) payload.get("method");
            
            if (url == null || method == null) {
                return ResponseEntity.badRequest().body("Missing required fields: url or method");
            }
            
            HttpHeaders headers = new HttpHeaders();
            headers.setContentType(MediaType.APPLICATION_JSON);
            
            HttpEntity<String> entity = new HttpEntity<>(headers);
            
            ResponseEntity<String> response;
            if ("GET".equalsIgnoreCase(method)) {
                response = restTemplate.exchange(url, HttpMethod.GET, entity, String.class);
            } else if ("POST".equalsIgnoreCase(method)) {
                String body = (String) payload.get("body");
                HttpEntity<String> postEntity = new HttpEntity<>(body, headers);
                response = restTemplate.exchange(url, HttpMethod.POST, postEntity, String.class);
            } else {
                return ResponseEntity.badRequest().body("Unsupported HTTP method: " + method);
            }
            
            return ResponseEntity.ok(response.getBody());
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Error processing webhook: " + e.getMessage());
        }
    }
    
    @PostMapping("/async-process")
    public CompletableFuture<ResponseEntity<String>> processWebhookAsync(@RequestBody Map<String, Object> payload) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                String url = (String) payload.get("url");
                String method = (String) payload.get("method");
                
                if (url == null || method == null) {
                    return ResponseEntity.badRequest().body("Missing required fields: url or method");
                }
                
                HttpHeaders headers = new HttpHeaders();
                headers.setContentType(MediaType.APPLICATION_JSON);
                
                HttpEntity<String> entity = new HttpEntity<>(headers);
                
                ResponseEntity<String> response;
                if ("GET".equalsIgnoreCase(method)) {
                    response = restTemplate.exchange(url, HttpMethod.GET, entity, String.class);
                } else if ("POST".equalsIgnoreCase(method)) {
                    String body = (String) payload.get("body");
                    HttpEntity<String> postEntity = new HttpEntity<>(body, headers);
                    response = restTemplate.exchange(url, HttpMethod.POST, postEntity, String.class);
                } else {
                    return ResponseEntity.badRequest().body("Unsupported HTTP method: " + method);
                }
                
                return ResponseEntity.ok(response.getBody());
            } catch (Exception e) {
                return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                        .body("Error processing webhook: " + e.getMessage());
            }
        });
    }
}